# Data processing utilities - imports from text_utils

from text_utils import TextProcessor, format_number

class DataAnalyzer:
    _processor: TextProcessor
    _values: list[int]

    def __init__(self, text: str, values: list[int]):
        self._processor = TextProcessor(text)
        self._values = values

    def summary(self) -> str:
        word_count = self._processor.word_count()
        total = 0
        for v in self._values:
            total += v
        avg = total / len(self._values) if len(self._values) > 0 else 0.0
        return f"Words: {word_count}, Avg: {avg:.1f}"

    def process_text(self) -> str:
        return self._processor.to_upper()

def calc_sum(values: list[int]) -> int:
    total: int = 0
    for v in values:
        total += v
    return total

def create_label(prefix: str, num: int) -> str:
    return prefix + " " + format_number(num)
